// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section id=\"intro\">\n<div class=\"section-header\">\n<div class=\"section-num\">01</div>\n<div class=\"section-title-group\">\n<h2>What is <span>Vue.js</span>?</h2>\n<p>A progressive framework for building user interfaces, designed to be adopted incrementally.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>Vue describes itself as progressive on purpose. You can drop it into a single page with a script tag and bind a handful of elements, or you can build an entire single page application with routing, global state, and server side rendering. The framework scales with the size of the problem instead of demanding a full rewrite before it gives you anything back.</p>\n<div>// Evan You, creator of Vue.js</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Declarative Rendering</h3>\n<p>You describe what the UI should look like for a given state. Vue figures out the DOM operations needed to get there, so you stop writing manual <code>appendChild</code> and <code>innerHTML</code> calls.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Reactivity</h3>\n<p>Plain JavaScript objects become trackable. Change a value once, and every part of the UI that reads it updates automatically, without you wiring up listeners by hand.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Component-Based</h3>\n<p>Interfaces are built from small, isolated, reusable pieces that each own their own template, logic, and styling. Complex UIs become a tree of simple ones.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>Progressive Adoption</h3>\n<p>Use it for one widget on a legacy server-rendered page, or for an entire enterprise application. The mental model doesn't change as the scope grows.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Single File Components</h3>\n<p><code>.vue</code> files colocate template, script, and scoped styles in one place. The thing that changes together lives together, instead of being split across three folders.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Approachable</h3>\n<p>The template syntax is close enough to HTML that you can read it without learning a new language first. Complexity is opt-in, not mandatory from line one.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">index.html (no build step required)</span>\n<span class=\"code-lang\">HTML</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>src</span>=<span>\"https://unpkg.com/vue@3/dist/vue.global.js\"</span>&gt;&lt;/<span>script</span>&gt;\n\n&lt;<span>div</span> <span>id</span>=<span>\"app\"</span>&gt;\n &lt;<span>h1</span>&gt;{{ message }}&lt;/<span>h1</span>&gt;\n &lt;<span>button</span> <span>@click</span>=<span>\"count++\"</span>&gt;Clicked {{ count }} times&lt;/<span>button</span>&gt;\n&lt;/<span>div</span>&gt;\n\n&lt;<span>script</span>&gt;\n <span>const</span> { <span>createApp</span>, <span>ref</span> } = Vue\n\n <span>createApp</span>({\n <span>setup</span>() {\n <span>const</span> message = <span>ref</span>(<span>'Hello, Vue!'</span>)\n <span>const</span> count = <span>ref</span>(0)\n <span>return</span> { message, count }\n }\n }).<span>mount</span>(<span>'#app'</span>)\n&lt;/<span>script</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>This is the same engine that powers full apps</h4>\n<p>The <code>ref()</code> and template syntax in this fifteen line snippet are identical to what you will use in a thousand file enterprise application. Vue does not have a separate beginner mode and pro mode, just more pieces you add as the project grows.</p>\n</div>\n</div>\n</section>\n<section id=\"mental-models\">\n<div class=\"section-header\">\n<div class=\"section-num\">02</div>\n<div class=\"section-title-group\">\n<h2>Mental <span class=\"tone-info\">Models</span></h2>\n<p>The handful of ideas that make everything else in Vue make sense once internalized.</p>\n</div>\n</div>\n<div class=\"mental-model\">\n<h3>State drives the DOM, not the other way around</h3>\n<p>In vanilla JavaScript you tell the browser exactly what to do: find this element, change its text, add this class. In Vue you instead describe the relationship between data and markup once, in the template, and then you only ever change the data. The framework is responsible for reconciling the DOM to match.</p>\n<ul>\n<li>You stop asking \"which element do I need to touch\" and start asking \"which piece of state changed\".</li>\n<li>Bugs shift from \"the DOM is out of sync\" to \"my state is wrong\", which is a much easier category of bug to reason about and to test.</li>\n<li>The template becomes a pure description of the UI for a given state, so two developers reading it can predict what renders without running the app.</li>\n</ul>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Imperative (vanilla JS)</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>let</span> count = 0\n<span>const</span> btn = document.<span>querySelector</span>(<span>'button'</span>)\n<span>const</span> out = document.<span>querySelector</span>(<span>'span'</span>)\n\nbtn.<span>addEventListener</span>(<span>'click'</span>, () =&gt; {\n count++\n <span>// you must remember to do this</span>\n <span>// every single place count changes</span>\n out.textContent = count\n})</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Declarative (Vue)</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre><span>const</span> count = <span>ref</span>(0)\n<span>// template, written once:</span>\n<span>// &lt;span&gt;{{ count }}&lt;/span&gt;</span>\n<span>// &lt;button @click=\"count++\"&gt;</span>\n\n<span>// nothing else to wire up, anywhere</span>\n<span>// the span always reflects count</span></pre></div>\n</div>\n</div>\n<div>\n<div class=\"sf-box\"><div class=\"sf-label\">You change</div><div class=\"sf-val\">count.value++</div></div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\"><div class=\"sf-label\">Proxy traps</div><div class=\"sf-val\">the .value set</div></div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\"><div class=\"sf-label\">Vue notifies</div><div class=\"sf-val\">subscribed effects</div></div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\"><div class=\"sf-label\">Compiler-optimized</div><div class=\"sf-val\">DOM patch runs</div></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>The compiler does more than you think</h4>\n<p>Vue's template compiler analyzes the template ahead of time and marks static parts of the tree so they are never re-diffed. Only the dynamic bindings you actually wrote are tracked at runtime. This is why Vue's reactivity is fast even though it looks \"automatic\": most of the work happens once, at compile time, not on every update.</p>\n</div>\n</div>\n</section>\n<section id=\"setup\">\n<div class=\"section-header\">\n<div class=\"section-num\">03</div>\n<div class=\"section-title-group\">\n<h2>Project <span class=\"tone-info\">Setup</span></h2>\n<p>Scaffolding a real, production-shaped Vue project in under a minute.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Terminal</span>\n<span class=\"code-lang\">BASH</span>\n</div>\n<div class=\"code-body\"><pre><span># the official scaffolding tool, built on Vite</span>\nnpm create vue@latest\n\n<span># it will prompt you for a project name, then ask</span>\n<span># a series of yes/no questions about what to include</span></pre></div>\n</div>\n<div class=\"step-list\">\n<div class=\"step\">\n<div class=\"step-num\">1</div>\n<div class=\"step-content\">\n<h4>TypeScript?</h4>\n<p>Say yes for anything beyond a throwaway prototype. Vue 3 was rewritten in TypeScript and the typing story for props, emits, and composables is excellent. Catching a typo in a prop name at compile time beats finding it in production.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">2</div>\n<div class=\"step-content\">\n<h4>JSX support?</h4>\n<p>Optional. Most Vue codebases use templates because they are easier to statically analyze and optimize at compile time. JSX is there for teams who specifically want render-function-style components.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">3</div>\n<div class=\"step-content\">\n<h4>Vue Router?</h4>\n<p>Say yes if you are building more than a single screen. It wires up <code>src/router</code> and a basic two-page example so you start from a working baseline instead of an empty folder.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">4</div>\n<div class=\"step-content\">\n<h4>Pinia?</h4>\n<p>Vue's official state management library. Say yes if more than one component needs to share state that isn't naturally passed down through props, such as the logged in user or a shopping cart.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">5</div>\n<div class=\"step-content\">\n<h4>Vitest, ESLint, Prettier?</h4>\n<p>All three are safe defaults. Vitest gives you a fast, Vite-native test runner from day one. ESLint with the Vue plugin catches template mistakes that plain JS linting would miss. Prettier removes formatting arguments from code review entirely.</p>\n</div>\n</div>\n</div>\n<div class=\"tree\">\nmy-vue-app/\n\u251c\u2500\u2500 <span>public/</span> <span>\u2190 static assets served as-is</span>\n\u251c\u2500\u2500 <span>src/</span>\n\u2502 \u251c\u2500\u2500 <span>assets/</span> <span>\u2190 images, global CSS, fonts</span>\n\u2502 \u251c\u2500\u2500 <span>components/</span> <span>\u2190 reusable .vue components</span>\n\u2502 \u251c\u2500\u2500 <span>composables/</span> <span>\u2190 reusable reactive logic (useX functions)</span>\n\u2502 \u251c\u2500\u2500 <span>views/</span> <span>\u2190 page-level components, one per route</span>\n\u2502 \u251c\u2500\u2500 <span>router/</span> <span>\u2190 route definitions and guards</span>\n\u2502 \u251c\u2500\u2500 <span>stores/</span> <span>\u2190 Pinia stores</span>\n\u2502 \u251c\u2500\u2500 <span>App.vue</span> <span>\u2190 root component, holds the router view</span>\n\u2502 \u2514\u2500\u2500 <span>main.ts</span> <span>\u2190 entry point, mounts the app</span>\n\u251c\u2500\u2500 <span>index.html</span> <span>\u2190 single HTML file, Vue mounts into it</span>\n\u251c\u2500\u2500 <span>vite.config.ts</span> <span>\u2190 build tool and dev server configuration</span>\n\u251c\u2500\u2500 <span>tsconfig.json</span>\n\u2514\u2500\u2500 <span>package.json</span>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">src/main.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>// entry point \u2014 Vue mounts the entire app into a single DOM element</span>\n<span>import</span> { createApp } <span>from</span> <span>'vue'</span>\n<span>import</span> App <span>from</span> <span>'./App.vue'</span>\n<span>import</span> router <span>from</span> <span>'./router'</span>\n<span>import</span> { createPinia } <span>from</span> <span>'pinia'</span>\n<span>import</span> <span>'./assets/main.css'</span>\n\n<span>const</span> app = <span>createApp</span>(App)\n\napp.<span>use</span>(<span>createPinia</span>()) <span>// register global state</span>\napp.<span>use</span>(router) <span>// register routing</span>\n\napp.<span>mount</span>(<span>'#app'</span>)</pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Vite, not webpack</h4>\n<p>Vue's tooling is built on Vite, which serves your source files over native browser ES modules during development instead of bundling everything up front. The dev server starts almost instantly and stays fast no matter how large the project grows, because nothing is bundled until you build for production.</p>\n</div>\n</div>\n</section>\n<section id=\"template-syntax\">\n<div class=\"section-header\">\n<div class=\"section-num\">04</div>\n<div class=\"section-title-group\">\n<h2>Template <span>Syntax</span></h2>\n<p>HTML with superpowers. Every directive is just JavaScript with a declarative wrapper.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>A Vue template compiles down to a render function, the same way JSX compiles down to <code>createElement</code> calls. The difference is that Vue's syntax stays close to plain HTML, with directives (attributes prefixed <code>v-</code>) acting as instructions to the compiler about which parts of the markup are dynamic.</p>\n</div>\n<table class=\"comparison-table\">\n<thead><tr><th>Directive</th><th>Purpose</th><th>Shorthand</th></tr></thead>\n<tbody>\n<tr><td><code>v-bind</code></td><td>Bind an attribute to an expression</td><td><code>:attr=\"value\"</code></td></tr>\n<tr><td><code>v-on</code></td><td>Attach an event listener</td><td><code>@click=\"handler\"</code></td></tr>\n<tr><td><code>v-if</code> / <code>v-else-if</code> / <code>v-else</code></td><td>Conditionally render, adds/removes from the DOM</td><td>none</td></tr>\n<tr><td><code>v-show</code></td><td>Toggle <code>display: none</code>, stays in the DOM</td><td>none</td></tr>\n<tr><td><code>v-for</code></td><td>Render a list, always pair with <code>:key</code></td><td>none</td></tr>\n<tr><td><code>v-model</code></td><td>Two-way binding on form inputs</td><td>none</td></tr>\n<tr><td><code>v-slot</code></td><td>Define which slot content goes where</td><td><code>#slotName</code></td></tr>\n</tbody>\n</table>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">ProductCard.vue (template block)</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>template</span>&gt;\n &lt;<span>div</span> <span>:class</span>=<span>\"{ 'card--sale': product.onSale }\"</span>&gt;\n &lt;<span>h2</span>&gt;{{ product.name }}&lt;/<span>h2</span>&gt;\n\n <span>&lt;!-- v-if removes the node entirely when false --&gt;</span>\n &lt;<span>span</span> <span>v-if</span>=<span>\"product.stock === 0\"</span>&gt;Sold out&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>v-else</span>&gt;{{ product.stock }} left&lt;/<span>span</span>&gt;\n\n <span>&lt;!-- v-for needs a stable, unique :key for each item --&gt;</span>\n &lt;<span>ul</span>&gt;\n &lt;<span>li</span> <span>v-for</span>=<span>\"tag in product.tags\"</span> <span>:key</span>=<span>\"tag\"</span>&gt;\n {{ tag }}\n &lt;/<span>li</span>&gt;\n &lt;/<span>ul</span>&gt;\n\n &lt;<span>button</span> <span>@click</span>=<span>\"addToCart(product)\"</span>&gt;\n Add to cart\n &lt;/<span>button</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>template</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Never use v-if and v-for on the same element</h4>\n<p>When both sit on one element, <code>v-if</code> evaluates against every item before the loop even narrows the list, which is wasteful and can throw if the variable from the loop is not yet defined. Move the condition to a wrapping element, or filter the source array with a computed property before looping over it.</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>v-if vs v-show, choosing correctly</h4>\n<p><code>v-if</code> has a higher toggle cost because it destroys and recreates the element and any child components, but a lower initial render cost because it renders nothing at all if false. <code>v-show</code> is the opposite: cheap to toggle, but it always renders once. Use <code>v-show</code> for things that flip often, like a tab panel, and <code>v-if</code> for things that rarely change, like an admin-only section.</p>\n</div>\n</div>\n</section>\n<section id=\"components\">\n<div class=\"section-header\">\n<div class=\"section-num\">05</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-info\">Components</span> &amp; Single File Components</h2>\n<p>Everything in a Vue app is a tree of components. The .vue file is what makes each one self-contained.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>A Single File Component bundles three concerns that traditionally lived in three separate files: the markup, the logic, and the styling. They are colocated because they change together. Renaming a CSS class almost always means updating the template in the same breath, so keeping them apart was never really separation of concerns, just separation of files.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">components/Counter.vue</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>// \"script setup\" is compile-time sugar: everything declared</span>\n<span>// here is automatically exposed to the template, no manual</span>\n<span>// return statement needed</span>\n<span>import</span> { ref } <span>from</span> <span>'vue'</span>\n\n<span>const</span> count = <span>ref</span>(0)\n\n<span>function</span> <span>increment</span>() {\n count.value++\n}\n&lt;/<span>script</span>&gt;\n\n&lt;<span>template</span>&gt;\n &lt;<span>button</span> <span>@click</span>=<span>\"increment\"</span>&gt;\n Count is {{ count }}\n &lt;/<span>button</span>&gt;\n&lt;/<span>template</span>&gt;\n\n&lt;<span>style</span> <span>scoped</span>&gt;\n<span>/* scoped: this CSS only applies to elements in THIS component */</span>\nbutton {\n background: #42d392;\n border-radius: 6px;\n}\n&lt;/<span>style</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>What \"scoped\" actually does</h4>\n<p>The compiler adds a unique data attribute to every element this component renders, then rewrites your CSS selectors to include that attribute. The styles never leak into child components or the rest of the page, and you never have to invent a unique class name prefix by hand to avoid collisions.</p>\n</div>\n</div>\n<div>\n<div class=\"tip-box\">\n<div class=\"tip-label\">Naming</div>\n<p>Use PascalCase for component file names and when referencing them in templates, so they are visually distinct from native HTML tags at a glance.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\">One job</div>\n<p>If a component's template is hard to summarize in one sentence, it is doing too much. Split it before the logic and the markup both become tangled.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\">Composition over depth</div>\n<p>Favor several small components composed together over one large component with many conditional branches inside its template.</p>\n</div>\n</div>\n</section>\n<section id=\"props-emits\">\n<div class=\"section-header\">\n<div class=\"section-num\">06</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-info\">Props</span> &amp; Emits</h2>\n<p>How data flows down into a component, and how events flow back up. One direction each, on purpose.</p>\n</div>\n</div>\n<div class=\"mental-model\">\n<h3>One-way data flow, by design</h3>\n<p>A child component never reaches up and changes its parent's state directly. Data flows down through props, and the child requests a change by emitting an event upward, which the parent decides how to handle. This keeps state ownership unambiguous: at any point in the tree, exactly one component is responsible for a given piece of data, and you can trace where it came from by reading upward.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">components/RatingStars.vue</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span> <span>lang</span>=<span>\"ts\"</span>&gt;\n<span>// defineProps describes the contract this component accepts</span>\n<span>const</span> props = <span>defineProps</span>&lt;{\n modelValue: <span>number</span>\n max?: <span>number</span>\n}&gt;()\n\n<span>// defineEmits declares the events this component can send up</span>\n<span>const</span> emit = <span>defineEmits</span>&lt;{\n (e: <span>'update:modelValue'</span>, value: <span>number</span>): <span>void</span>\n}&gt;()\n\n<span>function</span> <span>select</span>(star: <span>number</span>) {\n <span>// never mutate props.modelValue directly \u2014 emit instead</span>\n <span>emit</span>(<span>'update:modelValue'</span>, star)\n}\n&lt;/<span>script</span>&gt;\n\n&lt;<span>template</span>&gt;\n &lt;<span>span</span> <span>v-for</span>=<span>\"n in (props.max ?? 5)\"</span> <span>:key</span>=<span>\"n\"</span> <span>@click</span>=<span>\"select(n)\"</span>&gt;\n {{ n &lt;= props.modelValue ? '' : '' }}\n &lt;/<span>span</span>&gt;\n&lt;/<span>template</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Mutating a prop is a silent trap</h4>\n<p>Vue will warn in development if a child reassigns a prop, because the parent owns that value and any local change will be overwritten the next time the parent re-renders. If a component needs to tweak an incoming value locally, copy it into a local <code>ref</code> in <code>setup</code> instead of writing to the prop itself.</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>v-model on a component is sugar for this exact pattern</h4>\n<p>Writing <code>&lt;RatingStars v-model=\"rating\" /&gt;</code> on the parent expands to passing <code>:model-value=\"rating\"</code> down and listening for <code>@update:model-value=\"rating = $event\"</code> back up. It is the same props-down, emit-up flow, just spelled with less ceremony.</p>\n</div>\n</div>\n</section>\n<section id=\"reactivity\">\n<div class=\"section-header\">\n<div class=\"section-num\">07</div>\n<div class=\"section-title-group\">\n<h2>The <span>Reactivity System</span></h2>\n<p>Why changing a plain variable can update the screen. The mechanism underneath everything else.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>Vue 3's reactivity is built on JavaScript Proxies. Wrapping an object in a Proxy lets Vue intercept every property read and write. On a read, Vue records which effect (a render function, a computed, a watcher) is currently running and remembers that it depends on this property. On a write, Vue looks up everyone who depends on that property and reruns them. Nothing magic happens, it is dependency tracking implemented with native language features.</p>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">ref() \u2014 for any single value</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { ref } <span>from</span> <span>'vue'</span>\n\n<span>const</span> name = <span>ref</span>(<span>'Ada'</span>)\n<span>const</span> age = <span>ref</span>(30)\n\n<span>// must access through .value in script</span>\nconsole.<span>log</span>(name.value)\nage.value++\n\n<span>// the template auto-unwraps .value for you</span>\n<span>// &lt;p&gt;{{ name }} is {{ age }}&lt;/p&gt;</span></pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">reactive() \u2014 for objects</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { reactive } <span>from</span> <span>'vue'</span>\n\n<span>const</span> user = <span>reactive</span>({\n name: <span>'Ada'</span>,\n age: 30\n})\n\n<span>// no .value needed, access properties directly</span>\nconsole.<span>log</span>(user.name)\nuser.age++</pre></div>\n</div>\n</div>\n<table class=\"comparison-table\">\n<thead><tr><th>Use case</th><th>Reach for</th><th>Why</th></tr></thead>\n<tbody>\n<tr><td>A single primitive (string, number, boolean)</td><td><code>ref()</code></td><td>Primitives can't be proxied directly, so ref wraps them in an object with a tracked <code>.value</code></td></tr>\n<tr><td>A whole object or array you'll mutate in place</td><td><code>reactive()</code></td><td>Cleaner syntax, no <code>.value</code> noise, since the object itself can be proxied</td></tr>\n<tr><td>Destructuring fields out for separate use</td><td>avoid <code>reactive()</code>, use <code>toRefs()</code></td><td>Plain destructuring breaks the proxy connection and the value freezes</td></tr>\n<tr><td>You're not sure which</td><td><code>ref()</code></td><td>It works for both primitives and objects, and is the more common default in real codebases</td></tr>\n</tbody>\n</table>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>The classic reactivity-loss bug</h4>\n<p>Writing <code>const { name, age } = reactive({ name: 'Ada', age: 30 })</code> copies the values out at that instant. Later updates to the original object will not be reflected in <code>name</code> or <code>age</code>, because they are now disconnected plain variables. Use <code>toRefs()</code> when destructuring a reactive object so each field stays a connected <code>ref</code>.</p>\n</div>\n</div>\n</section>\n<section id=\"computed-watchers\">\n<div class=\"section-header\">\n<div class=\"section-num\">08</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-info\">Computed</span> Properties &amp; Watchers</h2>\n<p>Deriving state instead of duplicating it, and reacting to change instead of polling for it.</p>\n</div>\n</div>\n<div>\n<div class=\"hook-card\">\n<span class=\"hook-badge\">DERIVED</span>\n<div class=\"hook-name\">computed()</div>\n<div class=\"hook-subtitle\">value derived from other reactive state</div>\n<p>Wraps a getter function and caches the result. It only recalculates when one of its tracked dependencies actually changes, unlike a plain method, which reruns on every single render whether its inputs changed or not.</p>\n</div>\n<div class=\"hook-card\">\n<span class=\"hook-badge\">SIDE EFFECT</span>\n<div class=\"hook-name\">watch()</div>\n<div class=\"hook-subtitle\">run code when a specific source changes</div>\n<p>Watches one explicit reactive source and gives you both the old and new value when it fires. Use it for side effects that should not run on every render: an API call, a redirect, logging.</p>\n</div>\n<div class=\"hook-card\">\n<span class=\"hook-badge\">SIDE EFFECT</span>\n<div class=\"hook-name\">watchEffect()</div>\n<div class=\"hook-subtitle\">auto-tracks whatever it reads</div>\n<p>Runs immediately and again whenever any reactive value it read during its last run changes. There is no explicit dependency list, the function's own body defines its dependencies.</p>\n</div>\n<div class=\"hook-card\">\n<span class=\"hook-badge\">CLEANUP</span>\n<div class=\"hook-name\">onWatcherCleanup()</div>\n<div class=\"hook-subtitle\">cancel stale work inside a watcher</div>\n<p>Registers a cleanup callback that runs right before the watcher re-fires or is stopped, the standard place to abort an in-flight fetch so a slow, outdated request can't overwrite a newer result.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">computed vs method, the actual difference</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { ref, computed } <span>from</span> <span>'vue'</span>\n\n<span>const</span> items = <span>ref</span>([{ price: 10 }, { price: 25 }, { price: 8 }])\n\n<span>// computed: cached, only recalculates when items.value changes</span>\n<span>const</span> total = <span>computed</span>(() =&gt;\n items.value.<span>reduce</span>((sum, i) =&gt; sum + i.price, 0)\n)\n\n<span>// method: recalculates on EVERY re-render, even if items never changed</span>\n<span>function</span> <span>getTotal</span>() {\n <span>return</span> items.value.<span>reduce</span>((sum, i) =&gt; sum + i.price, 0)\n}</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">watch with cleanup, avoiding a race condition</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { ref, watch, onWatcherCleanup } <span>from</span> <span>'vue'</span>\n\n<span>const</span> searchTerm = <span>ref</span>(<span>''</span>)\n<span>const</span> results = <span>ref</span>([])\n\n<span>watch</span>(searchTerm, <span>async</span> (term) =&gt; {\n <span>const</span> controller = <span>new</span> <span>AbortController</span>()\n <span>onWatcherCleanup</span>(() =&gt; controller.<span>abort</span>())\n\n <span>const</span> res = <span>await</span> <span>fetch</span>(<span>`/api/search?q=${term}`</span>, { signal: controller.signal })\n results.value = <span>await</span> res.<span>json</span>()\n})</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Default to computed, reach for watch only for side effects</h4>\n<p>If you find yourself writing a watcher purely to set another piece of state, you almost always want a computed property instead. Watchers are for things that are not themselves UI state: network requests, writing to local storage, triggering an animation.</p>\n</div>\n</div>\n</section>\n<section id=\"composition-vs-options\">\n<div class=\"section-header\">\n<div class=\"section-num\">09</div>\n<div class=\"section-title-group\">\n<h2>Composition <span class=\"tone-info\">API</span> vs Options API</h2>\n<p>Two ways to write the same component. One organizes by option type, the other by feature.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>The Options API, Vue's original style, organizes a component by category: all the data in one block, all the methods in another, all the computed properties in a third. That reads well for small components, but on a large one, the logic for a single feature ends up scattered across five different blocks. The Composition API instead organizes by feature: everything related to one concern sits together, in the order it actually runs, which is also why it can be extracted into a reusable composable.</p>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Options API</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span>&gt;\n<span>export default</span> {\n data() {\n <span>return</span> { count: 0 }\n },\n computed: {\n doubled() { <span>return</span> <span>this</span>.count * 2 }\n },\n methods: {\n increment() { <span>this</span>.count++ }\n },\n mounted() {\n console.<span>log</span>(<span>'mounted'</span>)\n }\n}\n&lt;/<span>script</span>&gt;</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Composition API</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>import</span> { ref, computed, onMounted } <span>from</span> <span>'vue'</span>\n\n<span>const</span> count = <span>ref</span>(0)\n<span>const</span> doubled = <span>computed</span>(() =&gt; count.value * 2)\n\n<span>function</span> <span>increment</span>() { count.value++ }\n\n<span>onMounted</span>(() =&gt; {\n console.<span>log</span>(<span>'mounted'</span>)\n})\n&lt;/<span>script</span>&gt;</pre></div>\n</div>\n</div>\n<table class=\"comparison-table\">\n<thead><tr><th>Options API</th><th>Composition API</th><th>Notes</th></tr></thead>\n<tbody>\n<tr><td><code>data()</code></td><td><code>ref()</code> / <code>reactive()</code></td><td>State declared as variables instead of an object's properties</td></tr>\n<tr><td><code>computed: {}</code></td><td><code>computed()</code></td><td>Same caching behavior, called as a function instead of declared as a property</td></tr>\n<tr><td><code>methods: {}</code></td><td>plain functions</td><td>No <code>this</code> binding to worry about</td></tr>\n<tr><td><code>this.count</code></td><td><code>count.value</code></td><td>No implicit context object, everything is an explicit variable</td></tr>\n<tr><td>mixins</td><td>composables</td><td>Composables avoid the naming collisions and unclear origin of properties that mixins were known for</td></tr>\n</tbody>\n</table>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>This is not an either/or decision for the framework</h4>\n<p>Both APIs are first class and can be mixed within the same project, even within the same component in rare cases. New projects and official documentation default to Composition API with <code>&lt;script setup&gt;</code> because it has better TypeScript inference and makes logic reuse straightforward, which is the convention this guide follows from here on.</p>\n</div>\n</div>\n</section>\n<section id=\"lifecycle\">\n<div class=\"section-header\">\n<div class=\"section-num\">10</div>\n<div class=\"section-title-group\">\n<h2><span>Lifecycle</span> Hooks</h2>\n<p>Every component is born, updates some number of times, and eventually dies. Hooks let you act at each moment.</p>\n</div>\n</div>\n<div>\n<div class=\"lc-phase\">\n<div class=\"lc-phase-title\">Mount</div>\n<span class=\"lc-hook\">onBeforeMount</span>\n<span class=\"lc-hook\">onMounted</span>\n</div>\n<div class=\"lc-phase\">\n<div class=\"lc-phase-title\">Update</div>\n<span class=\"lc-hook\">onBeforeUpdate</span>\n<span class=\"lc-hook\">onUpdated</span>\n</div>\n<div class=\"lc-phase\">\n<div class=\"lc-phase-title\">Unmount</div>\n<span class=\"lc-hook\">onBeforeUnmount</span>\n<span class=\"lc-hook\">onUnmounted</span>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">composables/useClock.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { ref, onMounted, onUnmounted } <span>from</span> <span>'vue'</span>\n\n<span>export function</span> <span>useClock</span>() {\n <span>const</span> time = <span>ref</span>(<span>new</span> <span>Date</span>())\n <span>let</span> intervalId: <span>number</span>\n\n <span>onMounted</span>(() =&gt; {\n <span>// the element exists now, safe to start timers or read layout</span>\n intervalId = <span>setInterval</span>(() =&gt; { time.value = <span>new</span> <span>Date</span>() }, 1000)\n })\n\n <span>onUnmounted</span>(() =&gt; {\n <span>// always undo what onMounted set up, or you get a memory leak</span>\n <span>clearInterval</span>(intervalId)\n })\n\n <span>return</span> { time }\n}</pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Every onMounted side effect needs a matching cleanup</h4>\n<p>Intervals, event listeners on <code>window</code>, WebSocket connections, and subscriptions all keep running even after the component that created them is gone, unless you explicitly tear them down in <code>onUnmounted</code>. This is the single most common source of memory leaks and \"why is this firing twice\" bugs in real Vue apps.</p>\n</div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\">\u23f1</div>\n<div class=\"callout-body\">\n<h4>onMounted does not mean \"the data has loaded\"</h4>\n<p>It means the component's DOM now exists. If you fetch data inside <code>onMounted</code>, the template will render once with empty or loading state, then again once the data arrives and a ref updates. Plan your template's loading state for that gap rather than assuming data is present immediately.</p>\n</div>\n</div>\n</section>\n<section id=\"composables\">\n<div class=\"section-header\">\n<div class=\"section-num\">11</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-info\">Composables</span> \u2014 Reusable Reactive Logic</h2>\n<p>Vue's answer to \"how do I share stateful logic between components without inheritance or mixins\".</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>A composable is just a function, conventionally named starting with <code>use</code>, that calls reactive APIs like <code>ref</code>, <code>computed</code>, or lifecycle hooks, and returns the pieces a component needs. Because it is a plain function, you can call it from any component, compose several together, and reason about it with ordinary JavaScript scoping rules instead of learning a framework-specific mixing mechanism.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">composables/useFetch.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { ref, watchEffect, toValue } <span>from</span> <span>'vue'</span>\n\n<span>export function</span> <span>useFetch</span>&lt;T&gt;(url: <span>string</span> | (() =&gt; <span>string</span>)) {\n <span>const</span> data = <span>ref</span>&lt;T | <span>null</span>&gt;(<span>null</span>)\n <span>const</span> error = <span>ref</span>&lt;<span>Error</span> | <span>null</span>&gt;(<span>null</span>)\n <span>const</span> loading = <span>ref</span>(<span>true</span>)\n\n <span>watchEffect</span>(<span>async</span> () =&gt; {\n loading.value = <span>true</span>\n error.value = <span>null</span>\n <span>try</span> {\n <span>// toValue() unwraps refs, getters, or plain values uniformly</span>\n <span>const</span> res = <span>await</span> <span>fetch</span>(<span>toValue</span>(url))\n data.value = <span>await</span> res.<span>json</span>()\n } <span>catch</span> (e) {\n error.value = e <span>as</span> <span>Error</span>\n } <span>finally</span> {\n loading.value = <span>false</span>\n }\n })\n\n <span>return</span> { data, error, loading }\n}</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Using it in a component</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>import</span> { useFetch } <span>from</span> <span>'@/composables/useFetch'</span>\n\n<span>// one line gives the component data, error, and loading state</span>\n<span>// with no manual ref declarations or try/catch in the component itself</span>\n<span>const</span> { data: user, loading, error } = <span>useFetch</span>(<span>'/api/me'</span>)\n&lt;/<span>script</span>&gt;</pre></div>\n</div>\n<div class=\"step-list\">\n<div class=\"step\">\n<div class=\"step-num\">1</div>\n<div class=\"step-content\"><h4>Name it use-something</h4><p>The convention signals at a glance that this function uses reactive APIs and may have lifecycle ties, so it has rules about when and where it can be called.</p></div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">2</div>\n<div class=\"step-content\"><h4>Return refs, not raw values</h4><p>Returning <code>{ data: data.value }</code> snapshots a single moment in time. Returning <code>{ data }</code> keeps the live, reactive connection intact.</p></div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">3</div>\n<div class=\"step-content\"><h4>Composables can call other composables</h4><p>Just like components are built from components, composables can be built from smaller composables, the same way you'd extract a regular helper function.</p></div>\n</div>\n</div>\n</section>\n<section id=\"slots-provide\">\n<div class=\"section-header\">\n<div class=\"section-num\">12</div>\n<div class=\"section-title-group\">\n<h2>Slots &amp; <span class=\"tone-info\">Provide / Inject</span></h2>\n<p>Passing markup down instead of data, and skipping levels of the component tree when needed.</p>\n</div>\n</div>\n<table class=\"comparison-table\">\n<thead><tr><th>Mechanism</th><th>Passes</th><th>Direction</th></tr></thead>\n<tbody>\n<tr><td>Props</td><td>Data</td><td>Parent \u2192 direct child</td></tr>\n<tr><td>Slots</td><td>Template content / markup</td><td>Parent \u2192 direct child</td></tr>\n<tr><td>Emits</td><td>Events</td><td>Child \u2192 direct parent</td></tr>\n<tr><td>Provide / Inject</td><td>Data or functions</td><td>Ancestor \u2192 any descendant, skipping levels</td></tr>\n</tbody>\n</table>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Modal.vue \u2014 named and scoped slots</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>template</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"modal\"</span>&gt;\n &lt;<span>header</span>&gt;&lt;<span>slot</span> <span>name</span>=<span>\"header\"</span>&gt;Default title&lt;/<span>slot</span>&gt;&lt;/<span>header</span>&gt;\n\n <span>&lt;!-- the default, unnamed slot --&gt;</span>\n &lt;<span>main</span>&gt;&lt;<span>slot</span> /&gt;&lt;/<span>main</span>&gt;\n\n <span>&lt;!-- a scoped slot, passing data back UP to the parent's template --&gt;</span>\n &lt;<span>footer</span>&gt;&lt;<span>slot</span> <span>name</span>=<span>\"footer\"</span> <span>:close</span>=<span>\"() =&gt; visible = false\"</span> /&gt;&lt;/<span>footer</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>template</span>&gt;\n\n<span>&lt;!-- usage from the parent --&gt;</span>\n&lt;<span>Modal</span>&gt;\n &lt;<span>template</span> <span>#header</span>&gt;&lt;<span>h2</span>&gt;Confirm delete&lt;/<span>h2</span>&gt;&lt;/<span>template</span>&gt;\n &lt;<span>p</span>&gt;This cannot be undone.&lt;/<span>p</span>&gt;\n &lt;<span>template</span> <span>#footer</span>=<span>\"{ close }\"</span>&gt;\n &lt;<span>button</span> <span>@click</span>=<span>\"close\"</span>&gt;Cancel&lt;/<span>button</span>&gt;\n &lt;/<span>template</span>&gt;\n&lt;/<span>Modal</span>&gt;</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">provide / inject \u2014 skipping prop drilling</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>// in a high-level ancestor, e.g. App.vue</span>\n<span>import</span> { provide, ref } <span>from</span> <span>'vue'</span>\n<span>const</span> theme = <span>ref</span>(<span>'dark'</span>)\n<span>provide</span>(<span>'theme'</span>, theme)\n\n<span>// in ANY descendant, no matter how deeply nested</span>\n<span>import</span> { inject } <span>from</span> <span>'vue'</span>\n<span>const</span> theme = <span>inject</span>(<span>'theme'</span>) <span>// no props passed through every level</span></pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Provide / inject is for cross-cutting concerns, not general state</h4>\n<p>It is the right tool for things like theme, locale, or a form's validation context, things that genuinely apply to an entire subtree. For state shared across unrelated parts of an app, a Pinia store is more explicit and far easier to trace than an inject call with no visible source.</p>\n</div>\n</div>\n</section>\n<section id=\"router\">\n<div class=\"section-header\">\n<div class=\"section-num\">13</div>\n<div class=\"section-title-group\">\n<h2>Vue <span>Router</span></h2>\n<p>Turning a single page application into something that still feels like it has real, linkable pages.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">router/index.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { createRouter, createWebHistory } <span>from</span> <span>'vue-router'</span>\n\n<span>const</span> router = <span>createRouter</span>({\n history: <span>createWebHistory</span>(),\n routes: [\n { path: <span>'/'</span>, name: <span>'home'</span>, component: () =&gt; <span>import</span>(<span>'@/views/HomeView.vue'</span>) },\n { path: <span>'/products/:id'</span>, name: <span>'product'</span>, component: () =&gt; <span>import</span>(<span>'@/views/ProductView.vue'</span>) },\n { path: <span>'/account'</span>, name: <span>'account'</span>, component: () =&gt; <span>import</span>(<span>'@/views/AccountView.vue'</span>), meta: { requiresAuth: <span>true</span> } },\n ],\n})\n\n<span>// navigation guard: runs before every route change</span>\nrouter.<span>beforeEach</span>((to) =&gt; {\n <span>const</span> isLoggedIn = <span>checkAuth</span>()\n <span>if</span> (to.meta.requiresAuth &amp;&amp; !isLoggedIn) {\n <span>return</span> { name: <span>'login'</span> }\n }\n})\n\n<span>export default</span> router</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">views/ProductView.vue \u2014 reading route params</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>import</span> { useRoute, useRouter } <span>from</span> <span>'vue-router'</span>\n\n<span>const</span> route = <span>useRoute</span>() <span>// read-only info about the current route</span>\n<span>const</span> router = <span>useRouter</span>() <span>// imperative navigation</span>\n\nconsole.<span>log</span>(route.params.id) <span>// the :id segment from the URL</span>\n\n<span>function</span> <span>goBack</span>() {\n router.<span>push</span>({ name: <span>'home'</span> })\n}\n&lt;/<span>script</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Lazy-load every route</h4>\n<p>Writing the component as <code>() =&gt; import('@/views/ProductView.vue')</code> instead of a static import tells the bundler to split that view into its own chunk, downloaded only when the user actually navigates there. A user landing on the homepage never pays the bandwidth cost of the account settings page they may never visit.</p>\n</div>\n</div>\n</section>\n<section id=\"forms\">\n<div class=\"section-header\">\n<div class=\"section-num\">14</div>\n<div class=\"section-title-group\">\n<h2>Forms &amp; <span class=\"tone-info\">v-model</span></h2>\n<p>Two-way binding is sugar over an explicit value and an explicit event. Knowing the sugar helps when it doesn't behave as expected.</p>\n</div>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">What you write</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>input</span> <span>v-model</span>=<span>\"email\"</span> /&gt;</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">What it compiles to</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>input</span>\n <span>:value</span>=<span>\"email\"</span>\n <span>@input</span>=<span>\"email = $event.target.value\"</span>\n/&gt;</pre></div>\n</div>\n</div>\n<table class=\"comparison-table\">\n<thead><tr><th>Modifier</th><th>Effect</th></tr></thead>\n<tbody>\n<tr><td><code>v-model.lazy</code></td><td>Sync on the <code>change</code> event instead of every keystroke's <code>input</code> event</td></tr>\n<tr><td><code>v-model.number</code></td><td>Cast the bound value to a number automatically</td></tr>\n<tr><td><code>v-model.trim</code></td><td>Strip leading and trailing whitespace automatically</td></tr>\n</tbody>\n</table>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">SignupForm.vue \u2014 validation with vee-validate + zod</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>import</span> { useForm } <span>from</span> <span>'vee-validate'</span>\n<span>import</span> { toTypedSchema } <span>from</span> <span>'@vee-validate/zod'</span>\n<span>import</span> { z } <span>from</span> <span>'zod'</span>\n\n<span>const</span> schema = toTypedSchema(z.<span>object</span>({\n email: z.<span>string</span>().<span>email</span>(<span>'Enter a valid email'</span>),\n password: z.<span>string</span>().<span>min</span>(8, <span>'At least 8 characters'</span>),\n}))\n\n<span>const</span> { defineField, handleSubmit, errors } = <span>useForm</span>({ validationSchema: schema })\n<span>const</span> [email] = <span>defineField</span>(<span>'email'</span>)\n<span>const</span> [password] = <span>defineField</span>(<span>'password'</span>)\n\n<span>const</span> onSubmit = <span>handleSubmit</span>(<span>async</span> (values) =&gt; {\n <span>await</span> <span>fetch</span>(<span>'/api/signup'</span>, { method: <span>'POST'</span>, body: JSON.<span>stringify</span>(values) })\n})\n&lt;/<span>script</span>&gt;\n\n&lt;<span>template</span>&gt;\n &lt;<span>form</span> <span>@submit</span>=<span>\"onSubmit\"</span>&gt;\n &lt;<span>input</span> <span>v-model</span>=<span>\"email\"</span> /&gt;\n &lt;<span>span</span>&gt;{{ errors.email }}&lt;/<span>span</span>&gt;\n &lt;<span>input</span> <span>v-model</span>=<span>\"password\"</span> <span>type</span>=<span>\"password\"</span> /&gt;\n &lt;<span>span</span>&gt;{{ errors.password }}&lt;/<span>span</span>&gt;\n &lt;<span>button</span> <span>type</span>=<span>\"submit\"</span>&gt;Sign up&lt;/<span>button</span>&gt;\n &lt;/<span>form</span>&gt;\n&lt;/<span>template</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Why a schema library instead of hand-written if statements</h4>\n<p>The validation rules live in one declarative place, can run on both the client for instant feedback and the server for security, and the resulting TypeScript types are inferred automatically. Hand-written validation tends to drift out of sync between what the form checks and what the API actually requires.</p>\n</div>\n</div>\n</section>\n<section id=\"pinia\">\n<div class=\"section-header\">\n<div class=\"section-num\">15</div>\n<div class=\"section-title-group\">\n<h2>State Management with <span class=\"tone-info\">Pinia</span></h2>\n<p>For state that genuinely belongs to the whole app, not to one component's local concerns.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>Pinia is Vue's official state management library, and it replaced Vuex. The change was not cosmetic: Vuex required mutations as the only sanctioned way to change state, plus a separate actions layer for anything asynchronous, which added ceremony without adding safety in most apps. Pinia drops the mutations layer entirely, state is changed directly inside actions, and it was built from the ground up with TypeScript inference in mind rather than added on after the fact.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">stores/cart.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { defineStore } <span>from</span> <span>'pinia'</span>\n<span>import</span> { ref, computed } <span>from</span> <span>'vue'</span>\n\n<span>// the \"setup store\" style, mirrors script setup component syntax</span>\n<span>export const</span> useCartStore = <span>defineStore</span>(<span>'cart'</span>, () =&gt; {\n <span>const</span> items = <span>ref</span>&lt;{ id: <span>number</span>; price: <span>number</span> }[]&gt;([])\n\n <span>const</span> total = <span>computed</span>(() =&gt;\n items.value.<span>reduce</span>((sum, i) =&gt; sum + i.price, 0)\n )\n\n <span>function</span> <span>addItem</span>(item: { id: <span>number</span>; price: <span>number</span> }) {\n items.value.<span>push</span>(item) <span>// direct mutation, no separate mutation layer</span>\n }\n\n <span>return</span> { items, total, addItem }\n})</pre></div>\n</div>\n<div class=\"step-list\">\n<div class=\"step\">\n<div class=\"step-num\">1</div>\n<div class=\"step-content\"><h4>Register Pinia once, globally</h4><p><code>app.use(createPinia())</code> in <code>main.ts</code> sets up the system that every store plugs into.</p></div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">2</div>\n<div class=\"step-content\"><h4>Call the store function inside a component</h4><p><code>const cart = useCartStore()</code> gives you the live, reactive store. Calling it again elsewhere in the app returns the exact same instance, not a fresh copy.</p></div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">3</div>\n<div class=\"step-content\"><h4>Read and call directly in the template</h4><p><code>{{ cart.total }}</code> and <code>@click=\"cart.addItem(product)\"</code> work exactly like local component state, because under the hood it is built from the same <code>ref</code> and <code>computed</code> primitives.</p></div>\n</div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Don't reach for a store as the default</h4>\n<p>If only one component and its direct children need a value, props and local state are simpler to follow and to test. Promote state to Pinia only once two or more unrelated parts of the tree genuinely need to read or write the same thing.</p>\n</div>\n</div>\n</section>\n<section id=\"api-data\">\n<div class=\"section-header\">\n<div class=\"section-num\">16</div>\n<div class=\"section-title-group\">\n<h2>API &amp; <span>Data Fetching</span></h2>\n<p>Talking to a backend is the same problem in every framework: loading, success, and error states, every time.</p>\n</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>fetch / axios</h3>\n<p>The raw transport layer. <code>fetch</code> is built into the browser, <code>axios</code> adds request and response interceptors, automatic JSON parsing, and easier cancellation.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>@tanstack/vue-query</h3>\n<p>A server-state layer on top of any fetch function. Caching, deduplication of identical in-flight requests, background refetching, and retries come for free instead of being hand-rolled in every composable.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\">\u23f3</div>\n<h3>Loading &amp; error state</h3>\n<p>Every request has three states a template must account for: loading, success, and error. Skipping any one of them is how users end up staring at a blank screen with no explanation.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Using vue-query in a component</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>import</span> { useQuery } <span>from</span> <span>'@tanstack/vue-query'</span>\n\n<span>const</span> { data: posts, isLoading, isError } = <span>useQuery</span>({\n queryKey: [<span>'posts'</span>],\n queryFn: () =&gt; fetch(<span>'/api/posts'</span>).then(r =&gt; r.json()),\n})\n&lt;/<span>script</span>&gt;\n\n&lt;<span>template</span>&gt;\n &lt;<span>p</span> <span>v-if</span>=<span>\"isLoading\"</span>&gt;Loading...&lt;/<span>p</span>&gt;\n &lt;<span>p</span> <span>v-else-if</span>=<span>\"isError\"</span>&gt;Something went wrong.&lt;/<span>p</span>&gt;\n &lt;<span>ul</span> <span>v-else</span>&gt;\n &lt;<span>li</span> <span>v-for</span>=<span>\"post in posts\"</span> <span>:key</span>=<span>\"post.id\"</span>&gt;{{ post.title }}&lt;/<span>li</span>&gt;\n &lt;/<span>ul</span>&gt;\n&lt;/<span>template</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Why a query library instead of a hand-rolled composable</h4>\n<p>The naive version of <code>useFetch</code> from section 11 re-fetches every time the component mounts, even if another instance of the same component just fetched the same data seconds ago. A query library deduplicates that, caches it, and refetches in the background when the window regains focus, all behavior that becomes painful to maintain by hand at scale.</p>\n</div>\n</div>\n</section>\n<section id=\"testing\">\n<div class=\"section-header\">\n<div class=\"section-num\">17</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-info\">Testing</span> Vue Components</h2>\n<p>Confidence that the component behaves correctly for a user, not confidence that the implementation matches a mental model.</p>\n</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Vitest</h3>\n<p>A test runner built on Vite, so it shares the exact same module resolution and transform pipeline as the app it tests. Tests start fast and stay fast.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Vue Test Utils</h3>\n<p>The official low-level component testing library. Mounts a component in isolation and gives you helpers to find elements, trigger events, and assert on rendered output.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Playwright / Cypress</h3>\n<p>End-to-end tools that drive a real browser through entire user flows, catching integration issues that isolated component tests cannot see.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Counter.test.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { describe, it, expect } <span>from</span> <span>'vitest'</span>\n<span>import</span> { mount } <span>from</span> <span>'@vue/test-utils'</span>\n<span>import</span> Counter <span>from</span> <span>'./Counter.vue'</span>\n\n<span>describe</span>(<span>'Counter'</span>, () =&gt; {\n <span>it</span>(<span>'increments when clicked'</span>, <span>async</span> () =&gt; {\n <span>const</span> wrapper = <span>mount</span>(Counter)\n\n <span>expect</span>(wrapper.text()).<span>toContain</span>(<span>'Count is 0'</span>)\n\n <span>await</span> wrapper.<span>find</span>(<span>'button'</span>).<span>trigger</span>(<span>'click'</span>)\n\n <span>expect</span>(wrapper.text()).<span>toContain</span>(<span>'Count is 1'</span>)\n })\n})</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Test behavior, not internal state</h4>\n<p>The test above asserts on the rendered text a real user would see, not on the value of an internal <code>ref</code>. If the component's implementation changes later but the visible behavior stays the same, the test should still pass. Reaching into <code>wrapper.vm.count</code> directly couples the test to implementation details that are free to change.</p>\n</div>\n</div>\n</section>\n<section id=\"performance\">\n<div class=\"section-header\">\n<div class=\"section-num\">18</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-tip\">Performance</span></h2>\n<p>Vue is fast by default. These are the tools for the cases where default isn't enough.</p>\n</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>v-memo</h3>\n<p>Skips re-rendering a subtree as long as a list of dependency values are unchanged, similar in spirit to memoizing a row in a very large list that rarely changes.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>defineAsyncComponent</h3>\n<p>Loads a component's code on demand instead of in the initial bundle, ideal for anything below the fold or behind a modal that most visitors never open.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>shallowRef / shallowReactive</h3>\n<p>Only the top-level access is tracked, nested properties are not made reactive. Useful for very large objects, like a parsed CSV or a third-party SDK instance, where deep reactivity would be wasted work.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>KeepAlive</h3>\n<p>Wraps a dynamic component so it is detached rather than destroyed when switched away from, preserving its state and avoiding an expensive remount, such as keeping a long form's input intact while a user briefly checks another tab.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Lazy-loading a heavy component</span>\n<span class=\"code-lang\">VUE</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>script</span> <span>setup</span>&gt;\n<span>import</span> { defineAsyncComponent } <span>from</span> <span>'vue'</span>\n\n<span>// the chart library and its component are only downloaded</span>\n<span>// once this component actually renders</span>\n<span>const</span> RevenueChart = <span>defineAsyncComponent</span>(() =&gt;\n <span>import</span>(<span>'./RevenueChart.vue'</span>)\n)\n&lt;/<span>script</span>&gt;\n\n&lt;<span>template</span>&gt;\n &lt;<span>Suspense</span>&gt;\n &lt;<span>RevenueChart</span> /&gt;\n &lt;<span>template</span> <span>#fallback</span>&gt;\n &lt;<span>p</span>&gt;Loading chart...&lt;/<span>p</span>&gt;\n &lt;/<span>template</span>&gt;\n &lt;/<span>Suspense</span>&gt;\n&lt;/<span>template</span>&gt;</pre></div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>The most common performance bug is a missing or unstable :key</h4>\n<p>Using the array index as the key for a <code>v-for</code> list that can be reordered, filtered, or have items inserted in the middle forces Vue to patch the wrong DOM nodes against the wrong data, which causes input focus to jump, transitions to glitch, and form state to attach to the wrong row. Always key on a stable, unique identifier from the data itself.</p>\n</div>\n</div>\n</section>\n<section id=\"patterns\">\n<div class=\"section-header\">\n<div class=\"section-num\">19</div>\n<div class=\"section-title-group\">\n<h2>Advanced <span class=\"tone-info\">Patterns</span></h2>\n<p>The techniques that come up once an app outgrows the basics.</p>\n</div>\n</div>\n<div class=\"step-list\">\n<div class=\"step\">\n<div class=\"step-num\">1</div>\n<div class=\"step-content\">\n<h4>Teleport</h4>\n<p>Renders a component's markup into a different part of the actual DOM, while it stays in its logical place in the component tree. The standard fix for a modal or tooltip trapped inside a parent with <code>overflow: hidden</code> or a low <code>z-index</code> stacking context.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">2</div>\n<div class=\"step-content\">\n<h4>Dynamic components with &lt;component :is&gt;</h4>\n<p>Swaps which component renders based on a reactive value, the basis for tabbed interfaces, step wizards, and plugin-style widget systems where the exact component isn't known until runtime.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">3</div>\n<div class=\"step-content\">\n<h4>Custom directives</h4>\n<p>For DOM-level behavior that doesn't map cleanly to a component, like a <code>v-focus</code> directive that focuses an input as soon as it mounts, or a <code>v-click-outside</code> that closes a dropdown.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">4</div>\n<div class=\"step-content\">\n<h4>Renderless components</h4>\n<p>Components that contain logic and state but no markup of their own, exposing everything through a scoped slot so the parent decides entirely how it looks while the component owns entirely how it behaves.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">5</div>\n<div class=\"step-content\">\n<h4>Suspense for async setup</h4>\n<p>If a component's <code>&lt;script setup&gt;</code> uses a top-level <code>await</code>, wrapping it in <code>&lt;Suspense&gt;</code> lets you declare a single fallback for the entire async boundary instead of threading a loading flag through every component involved.</p>\n</div>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">directives/clickOutside.ts</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { <span>type</span> Directive } <span>from</span> <span>'vue'</span>\n\n<span>export const</span> vClickOutside: Directive&lt;HTMLElement, () =&gt; <span>void</span>&gt; = {\n mounted(el, binding) {\n el.<span>_clickHandler</span> = (event: MouseEvent) =&gt; {\n <span>if</span> (!el.<span>contains</span>(event.target <span>as</span> <span>Node</span>)) {\n binding.value()\n }\n }\n document.<span>addEventListener</span>(<span>'click'</span>, el._clickHandler)\n },\n unmounted(el) {\n document.<span>removeEventListener</span>(<span>'click'</span>, el._clickHandler)\n },\n}</pre></div>\n</div>\n</section>\n<section id=\"tooling\">\n<div class=\"section-header\">\n<div class=\"section-num\">20</div>\n<div class=\"section-title-group\">\n<h2>Tooling &amp; <span>Deployment</span></h2>\n<p>The professional Vue developer's toolkit, from a fresh clone to a live production URL.</p>\n</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Vite</h3>\n<p>Build tool and dev server. Instant hot module replacement, native ESM in development, fast Rollup-based production bundles. The default for every modern Vue project.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>TypeScript</h3>\n<p>Type safety across components, props, emits, and Pinia stores. Vue's tooling, including the Volar editor extension, was built specifically to understand <code>.vue</code> files with full type checking.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Tailwind CSS</h3>\n<p>Utility classes directly in the template, colocated with the markup they style, removing the back and forth between a component file and a separate stylesheet.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>ESLint + Prettier</h3>\n<p>ESLint with <code>eslint-plugin-vue</code> catches template-level mistakes plain JavaScript linting cannot see, such as a missing <code>:key</code> on a <code>v-for</code>. Prettier removes formatting debates from code review.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Vitest</h3>\n<p>Vite-native, fast, and Jest-API-compatible, so most existing testing knowledge transfers directly without learning a second tool's conventions.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Vercel / Netlify</h3>\n<p>Push to a Git repository and the build runs automatically. Or build locally with <code>npm run build</code> and upload the resulting <code>dist/</code> folder to any static host or CDN.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Essential Dependencies</span>\n<span class=\"code-lang\">BASH</span>\n</div>\n<div class=\"code-body\"><pre><span># Routing</span>\nnpm install vue-router\n\n<span># State management</span>\nnpm install pinia\n\n<span># Forms + validation</span>\nnpm install vee-validate @vee-validate/zod zod\n\n<span># Server state</span>\nnpm install @tanstack/vue-query\n\n<span># Styling</span>\nnpm install -D tailwindcss @tailwindcss/vite\n\n<span># Testing</span>\nnpm install -D vitest @vue/test-utils jsdom\n\n<span># Linting</span>\nnpm install -D eslint eslint-plugin-vue prettier</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Full-stack? Use Nuxt</h4>\n<p>If you need server-side rendering, file-based routing generated automatically from your folder structure, API routes, and image optimization out of the box, <strong>Nuxt</strong> is the production choice. It is Vue plus a server framework, the same relationship Next.js has to React. <code>npx nuxi@latest init</code></p>\n</div>\n</div>\n<div class=\"divider\"><div class=\"divider-line\"></div><div class=\"divider-text\">// React vs Vue \u2014 The Complete Map</div><div class=\"divider-line\"></div></div>\n<table class=\"comparison-table\">\n<thead><tr><th>React Concept</th><th>Vue Equivalent</th><th>Notes</th></tr></thead>\n<tbody>\n<tr><td>JSX</td><td>Templates (or optional JSX)</td><td>Templates compile to optimized render functions; static parts are hoisted automatically</td></tr>\n<tr><td><code>useState</code></td><td><code>ref()</code> / <code>reactive()</code></td><td>Proxy-based tracking instead of a re-render-and-diff cycle per update</td></tr>\n<tr><td><code>useEffect</code></td><td><code>watchEffect()</code> / <code>watch()</code></td><td>Vue separates \"runs after render\" (<code>onMounted</code>/<code>onUpdated</code>) from \"runs when a value changes\" (<code>watch</code>)</td></tr>\n<tr><td><code>useMemo</code> / <code>useCallback</code></td><td><code>computed()</code></td><td>Automatic dependency tracking, no manual dependency array to maintain</td></tr>\n<tr><td>Custom Hooks</td><td>Composables</td><td>Same idea: a function starting with <code>use</code> that encapsulates reactive logic</td></tr>\n<tr><td>Context API</td><td><code>provide</code> / <code>inject</code></td><td>Both skip prop drilling for cross-cutting concerns across the tree</td></tr>\n<tr><td>Redux / Zustand</td><td>Pinia</td><td>Pinia's setup stores read almost identically to a Composition API component</td></tr>\n<tr><td>React Router</td><td>Vue Router</td><td>Comparable APIs: nested routes, guards, lazy-loaded route components</td></tr>\n<tr><td>React Hook Form</td><td>vee-validate</td><td>Both pair with Zod for schema-based validation</td></tr>\n<tr><td>TanStack Query (React)</td><td>TanStack Query (Vue)</td><td>Same library family, a Vue-specific adapter with the same caching model</td></tr>\n<tr><td>Error Boundaries</td><td><code>onErrorCaptured</code></td><td>A lifecycle hook that catches errors thrown by descendant components</td></tr>\n<tr><td>Portals (<code>createPortal</code>)</td><td><code>&lt;Teleport&gt;</code></td><td>Both render markup into a different DOM location while staying in the logical tree</td></tr>\n<tr><td>Next.js</td><td>Nuxt</td><td>Full-stack meta-framework: SSR, file-based routing, API routes</td></tr>\n<tr><td>Vitest + Testing Library</td><td>Vitest + Vue Test Utils</td><td>Both encourage testing rendered behavior over internal implementation</td></tr>\n</tbody>\n</table>\n</section>";

